const apiResponse = $json;
const passStateData = $('Pass State').item.json;

const prevCompanies = passStateData.allCompanies || [];
const newCompanies = apiResponse.results || [];
const cursor = apiResponse.paging?.next?.after || null;

return {
  json: {
    after: cursor,
    allCompanies: [...prevCompanies, ...newCompanies]
  }
};

const allCompanies = $input.first().json.allCompanies || [];
return allCompanies.map(company => ({
  json: {
    id: String(company.id),
    properties: company.properties || {}
  }
}));

const items = $input.all();
const companies = items.map((item, index) => ({
  index,
  name: item.json.companyName,
  domain: item.json.domain,
}));

const prompt = 'You are an expert at identifying corporate subsidiaries and branches.\n\n'
  + 'For each company below, determine if it is:\n'
  + '- INDEPENDENT (standalone business)\n'
  + '- SUBSIDIARY/BRANCH of a larger parent company\n\n'
  + 'ONLY classify as SUBSIDIARY when you have UNAMBIGUOUS evidence from one of these categories:\n\n'
  + '1. FORTUNE GLOBAL 500 / BIG 4 with explicit geography:\n'
  + '   - "KPMG Spain", "Deloitte Netherlands", "PwC Austria" -> subsidiary of the global firm\n'
  + '   - But "KPMG" alone (no geography) -> INDEPENDENT (could be the parent itself)\n\n'
  + '2. EXPLICIT WORDS in the name: "Branch", "Office", "Division", "Filiale", "Niederlassung", "Sucursal"\n\n'
  + '3. FAMOUS ACQUISITIONS you are 100% certain about:\n'
  + '   - Instagram -> Meta, YouTube -> Alphabet, LinkedIn -> Microsoft, WhatsApp -> Meta\n'
  + '   - B&R -> ABB, Numab -> Johnson & Johnson\n'
  + '   - Do NOT guess acquisitions. If you are not 100% sure, classify as INDEPENDENT.\n\n'
  + '4. SUBDOMAINS of a known parent: e.g., deco.cscec.com -> cscec.com\n\n'
  + '5. DUPLICATE ENTRIES: Two entries clearly being the same company with different TLDs (e.g., preh.com and preh.de)\n\n'
  + 'ALWAYS INDEPENDENT \u2014 never classify these as subsidiaries:\n'
  + '- Government agencies, ministries, public authorities\n'
  + '- Universities, university hospitals, research institutes\n'
  + '- Non-profits, associations, foundations (e.V., Stiftung, Verband, Kuratorium)\n'
  + '- Airlines (e.g., Ita Airways, Vueling, Eurowings)\n'
  + '- Companies with geography in their BRAND NAME (e.g., Berlin Brands Group, Heidelberg Engineering, Swiss Life, Ita Airways)\n'
  + '- Companies with regional descriptors (Nordic, European, EMEA, Deutschland)\n'
  + '- Companies with country-code TLDs (.de, .es, .uk, .ch, .at) \u2014 this is NOT evidence of being a subsidiary\n'
  + '- Consumer email/cloud domains (icloud.com, me.com, gmail.com, outlook.com) \u2014 these are NOT company domains\n\n'
  + 'WHEN IN DOUBT -> INDEPENDENT. A wrong "independent" label is harmless. A wrong "subsidiary" label causes incorrect data.\n\n'
  + 'COMPANIES TO CLASSIFY:\n'
  + companies.map(c => {
    let line = '[' + c.index + '] "' + c.name + '" (domain: ' + (c.domain || 'none') + ')';
    return line;
  }).join('\n')
  + '\n\nReturn ONLY a valid JSON array (no markdown, no explanation):\n'
  + '[{"index": 0, "isSubsidiary": false, "parentCompany": null, "parentDomain": null}]\n\n'
  + 'Rules:\n'
  + '- For independent companies: isSubsidiary=false, parentCompany=null, parentDomain=null\n'
  + '- For subsidiaries: isSubsidiary=true, parentCompany=parent name, parentDomain=parent primary domain (e.g., "kpmg.com" not "kpmg.es")\n'
  + '- When unsure, ALWAYS default to independent (isSubsidiary=false)';

const companyData = items.map(item => item.json);

return [{
  json: {
    prompt,
    companyData: JSON.stringify(companyData),
    companyCount: companies.length
  }
}];

const geminiResponse = $input.first().json;
const prepData = $('Prepare Gemini Batch').first().json;
const companyData = JSON.parse(prepData.companyData);

let classifications = [];
try {
  const text = geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text || '';
  const cleaned = text.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  classifications = JSON.parse(cleaned);
} catch (e) {
  classifications = companyData.map((_, i) => ({
    index: i,
    isSubsidiary: false,
    parentCompany: null,
    parentDomain: null
  }));
}

return companyData.map((company, index) => {
  const classification = classifications.find(c => c.index === index) || {
    isSubsidiary: false,
    parentCompany: null,
    parentDomain: null
  };

  const enrichmentDomain = classification.isSubsidiary && classification.parentDomain
    ? classification.parentDomain
    : company.domain;

  return {
    json: {
      companyId: company.companyId,
      companyName: company.companyName,
      domain: company.domain,
      linkedinUrl: company.linkedinUrl,
      existingEmployeeCount: company.existingEmployeeCount,
      isSubsidiary: classification.isSubsidiary || false,
      parentCompany: classification.parentCompany || null,
      parentDomain: classification.parentDomain || null,
      enrichmentDomain: enrichmentDomain
    }
  };
});

const items = $input.all();
const companies = [];
const allCompanyData = [];

for (const item of items) {
  const d = item.json;
  allCompanyData.push(d);

  const entry = {};
  if (d.enrichmentDomain) entry.domain = d.enrichmentDomain;
  if (d.linkedinUrl && !d.isSubsidiary) entry.linkedin_url = d.linkedinUrl;
  if (d.isSubsidiary && d.enrichmentDomain) {
    entry.domain = d.enrichmentDomain;
  }

  if (Object.keys(entry).length > 0) {
    companies.push(entry);
  }
}

return [{
  json: {
    batchPayload: { companies },
    allCompanyData: JSON.stringify(allCompanyData),
    totalCompanies: allCompanyData.length,
    batchSize: companies.length
  }
}];

const submitResponse = $json;
const batchData = $('Build Batch Request').first().json;

return {
  json: {
    requestId: submitResponse.id || submitResponse.request_id || submitResponse.data?.id || '',
    pollCount: 0,
    maxPolls: 20,
    allCompanyData: batchData.allCompanyData,
    totalCompanies: batchData.totalCompanies
  }
};

const apiResponse = $json;
const state = $('Wait 15s').item.json;

const isCompleted = apiResponse.status === 'completed' || apiResponse.data?.status === 'completed';
const pollCount = (state.pollCount || 0) + 1;
const maxReached = pollCount >= (state.maxPolls || 20);

return {
  json: {
    pollResponse: apiResponse,
    requestId: state.requestId,
    pollCount,
    maxPolls: state.maxPolls || 20,
    allCompanyData: state.allCompanyData,
    totalCompanies: state.totalCompanies,
    isComplete: isCompleted || maxReached
  }
};

return {
  json: {
    requestId: $json.requestId,
    pollCount: $json.pollCount,
    maxPolls: $json.maxPolls,
    allCompanyData: $json.allCompanyData,
    totalCompanies: $json.totalCompanies
  }
};

const input = $input.first().json;
const pollResponse = input.pollResponse || input;
const allCompanyData = JSON.parse(input.allCompanyData || '[]');
const results = pollResponse.results || [];

const resultsByDomain = {};
const resultsByLinkedin = {};
for (const r of results) {
  if (r.domain) resultsByDomain[r.domain.toLowerCase()] = r;
  if (r.linkedin_url) resultsByLinkedin[r.linkedin_url.toLowerCase()] = r;
}

return allCompanyData.map(company => {
  let match = null;
  if (company.enrichmentDomain) {
    match = resultsByDomain[company.enrichmentDomain.toLowerCase()] || null;
  }
  if (!match && company.linkedinUrl && !company.isSubsidiary) {
    match = resultsByLinkedin[company.linkedinUrl.toLowerCase()] || null;
  }

  let employeeCount = 0;
  if (match && match.result && typeof match.result === 'object') {
    employeeCount = match.result.estimated_number_of_employees || 0;
  } else if (match) {
    employeeCount = match.estimated_number_of_employees || 0;
  }

  return {
    json: {
      companyId: company.companyId,
      companyName: company.companyName,
      domain: company.domain,
      linkedinUrl: company.linkedinUrl || '',
      enrichmentDomain: company.enrichmentDomain || '',
      isSubsidiary: company.isSubsidiary || false,
      parentCompany: company.parentCompany || '',
      parentCompanyValue: company.parentCompanyValue || '',
      employeeCount: parseInt(employeeCount) || 0,
      matchFound: match !== null,
      matchDomain: match ? match.domain : 'no match'
    }
  };
});

const d = $json;
let enrichmentSource = 'Amplemarket';
if (d.isSubsidiary && d.parentCompany) {
  enrichmentSource = 'Amplemarket (parent: ' + d.parentCompany + ')';
}

return {
  json: {
    companyId: d.companyId,
    companyName: d.companyName,
    domain: d.domain,
    isSubsidiary: d.isSubsidiary,
    parentCompany: d.parentCompany,
    parentCompanyValue: d.parentCompanyValue || '',
    employeeCount: d.employeeCount,
    enrichmentSource
  }
};

let companyId, companyName, domain, isSubsidiary, parentCompany, parentCompanyValue;

try {
  const cd = $('Check Resolved').item.json;
  companyId = cd.companyId;
  companyName = cd.companyName;
  domain = cd.domain;
  isSubsidiary = cd.isSubsidiary;
  parentCompany = cd.parentCompany;
  parentCompanyValue = cd.parentCompanyValue;
} catch(e) {
  companyId = $json.companyId;
  companyName = $json.companyName;
  domain = $json.domain;
  isSubsidiary = $json.isSubsidiary;
  parentCompany = $json.parentCompany;
  parentCompanyValue = $json.parentCompanyValue;
}

return {
  json: {
    companyId: companyId || '',
    companyName: companyName || '',
    domain: domain || '',
    isSubsidiary: isSubsidiary || false,
    parentCompany: parentCompany || null,
    parentCompanyValue: parentCompanyValue || '',
    employeeCount: 5,
    enrichmentSource: 'Estimated'
  }
};

const r = $('Preserve Pre-Update').item.json;
return {
  json: {
    companyId: r.companyId,
    companyName: r.companyName,
    domain: r.domain,
    isSubsidiary: r.isSubsidiary,
    parentCompany: r.parentCompany,
    parentCompanyValue: r.parentCompanyValue || '',
    employeeCount: r.employeeCount,
    enrichmentSource: r.enrichmentSource
  }
};

const items = $json.data || [];

if (items.length === 0) {
  return { json: { message: 'No companies processed for employee enrichment today.' } };
}

const today = new Date().toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });
let amplemarket = 0;
let parentEnriched = 0;
let estimated = 0;
const details = [];

for (const d of items) {
  if (d.enrichmentSource === 'Estimated') {
    estimated++;
    details.push('\u26aa ' + d.companyName + ' \u2192 ' + d.employeeCount + ' employees (Default)');
  } else if (d.enrichmentSource && d.enrichmentSource.startsWith('Amplemarket (parent:')) {
    parentEnriched++;
    const parentLink = d.parentCompanyValue && d.parentCompanyValue.startsWith('https')
      ? '<' + d.parentCompanyValue + '|' + d.parentCompany + '>'
      : (d.parentCompany || 'unknown');
    details.push('\ud83c\udfe2 ' + d.companyName + ' \u2192 ' + d.employeeCount + ' employees (parent: ' + parentLink + ')');
  } else {
    amplemarket++;
    details.push('\u2705 ' + d.companyName + ' \u2192 ' + d.employeeCount + ' employees (Amplemarket)');
  }
}

const total = items.length;
const message = '*Employee Count Enrichment v3.0 \u2014 ' + today + '*\n'
  + 'Total processed: ' + total + '\n'
  + '\u2705 Amplemarket: ' + amplemarket + '\n'
  + '\ud83c\udfe2 Parent enriched: ' + parentEnriched + '\n'
  + '\u26aa Default: ' + estimated + '\n\n'
  + '*Details:*\n'
  + details.slice(0, 50).join('\n');

return { json: { message } };

const items = $input.all();
const parentDomains = new Set();
const allCompanyData = [];

for (const item of items) {
  const d = item.json;
  allCompanyData.push(d);
  if (d.isSubsidiary && d.parentDomain) {
    parentDomains.add(d.parentDomain);
  }
}

const domains = [...parentDomains];
let searchBody;
if (domains.length > 0) {
  searchBody = {
    filterGroups: [{ filters: [{ propertyName: 'domain', operator: 'IN', values: domains }] }],
    properties: ['name', 'domain'],
    limit: 100
  };
} else {
  searchBody = {
    filterGroups: [{ filters: [{ propertyName: 'domain', operator: 'EQ', value: '__no_parent_domains__' }] }],
    properties: ['name', 'domain'],
    limit: 1
  };
}

return [{
  json: {
    parentDomains: domains,
    allCompanyData: JSON.stringify(allCompanyData),
    hasParents: domains.length > 0,
    searchBody: JSON.stringify(searchBody)
  }
}];

const input = $input.first().json;
const prepData = $('Prep Parent Lookup').first().json;
const allCompanyData = JSON.parse(prepData.allCompanyData);

const hsResults = input.results || [];

const domainToHsUrl = {};
for (const r of hsResults) {
  const domain = (r.properties && r.properties.domain || '').toLowerCase();
  const companyId = r.id;
  if (domain && companyId) {
    domainToHsUrl[domain] = 'https://app-eu1.hubspot.com/contacts/142047914/company/' + companyId;
  }
}

return allCompanyData.map(company => {
  let parentCompanyValue = '';
  if (company.isSubsidiary && company.parentCompany) {
    if (company.parentDomain && domainToHsUrl[company.parentDomain.toLowerCase()]) {
      parentCompanyValue = domainToHsUrl[company.parentDomain.toLowerCase()];
    } else {
      parentCompanyValue = company.parentCompany;
    }
  }

  return {
    json: {
      companyId: company.companyId,
      companyName: company.companyName,
      domain: company.domain,
      linkedinUrl: company.linkedinUrl || '',
      existingEmployeeCount: company.existingEmployeeCount || 0,
      isSubsidiary: company.isSubsidiary || false,
      parentCompany: company.parentCompany || null,
      parentDomain: company.parentDomain || null,
      enrichmentDomain: company.enrichmentDomain || company.domain,
      parentCompanyValue
    }
  };
});
